#include <iostream>
#include <vector>

int main()
{
    int n{};
    std::cin >> n;

    std::vector<bool> flags;
    for (int i = 0; i < n; ++i)
    {
        int x{};
        std::cin >> x;
        flags.push_back(x != 0);
    }

    int count = 0;
    for (int i = 0; i < (int)flags.size(); ++i)
    {
        if (flags[i])
            ++count;
    }

    std::cout << "True count: " << count << '\n';

    return 0;
}

