solution_code:
#include <iostream>
#include <vector>

std::vector<bool> sieve(int n)
{
    std::vector<bool> is_prime(n + 1, true);
    is_prime[0] = false;
    if (n >= 1) is_prime[1] = false;

    for (int i = 2; i <= n; ++i)
    {
        if (is_prime[i])
        {
            for (int j = 2 * i; j <= n; j += i)
                is_prime[j] = false;
        }
    }

    return is_prime;
}

int main()
{
    int n{};
    std::cin >> n;

    std::vector<bool> is_prime = sieve(n);

    for (int i = 2; i <= n; ++i)
    {
        if (is_prime[i])
            std::cout << i << '\n';
    }

    return 0;
}
